/*
Write a function that takes an array of numbers as input and returns
the number of elements in the array that are greater than 10 and both
first and last digits of a number are odd (1, 3, 5, 7, 9).
For example:
p146_specialFilter([15, -73, 14, -15]) => 1
p146_specialFilter([33, -2, -3, 45, 21, 109]) => 2
*/
#include "verification_stdlib.h"
#include "verification_list.h"
#include "int_array_def.h"

/*@ Extern Coq (problem_146_pre: list Z -> Prop)
               (problem_146_spec: list Z -> Z -> Prop)
               (special_filter_prefix: Z -> list Z -> Z -> Prop)
               (special_filter_int_range: list Z -> Prop)
               (first_digit_state: Z -> Z -> Prop)
               (special_number_c: Z -> Prop)
               (not_special_number_c: Z -> Prop) */
/*@ Import Coq Require Import p146_specialFilter */

int p146_specialFilter(int* nums, int nums_size)
/*@ With input_l
    Require
        0 <= nums_size && nums_size < INT_MAX &&
        nums_size == Zlength(input_l) &&
        problem_146_pre(input_l) &&
        special_filter_int_range(input_l) &&
        IntArray::full(nums, nums_size, input_l)
    Ensure
        problem_146_spec(input_l, __return) &&
        IntArray::full(nums, nums_size, input_l)
*/
{
    int num=0;
    int i;

    for (i=0;i<nums_size;i++) {
        if (nums[i]>10)
        {
            int first;
            int last;
            first = nums[i];
            last = nums[i] % 10;

            while (first >= 10) {
                first /= 10;
            }
            if (first % 2 == 1 && last % 2 == 1) {

                num+=1;
            }

        }

    }
    return num;
}

/*
From a given vector of integers, generate a vector of rolling maximum element found until given moment
in the sequence. Output is written into pre-allocated array `out` of the same size.
>>> p009_rolling_max({1, 2, 3, 2, 3, 4, 2}, out)
out = {1, 2, 3, 3, 3, 4, 4}
*/
#include "verification_stdlib.h"
#include "verification_list.h"
#include "int_array_def.h"

/*@ Extern Coq (problem_9_pre: Prop)
               (problem_9_spec: list Z -> list Z -> Prop)
               (list_int_range: list Z -> Prop)
               (rolling_max_f: Z -> list Z -> list Z)
               (running_max_val: Z -> list Z -> Z) */
/*@ Import Coq Require Import p009_rolling_max */

int *p009_rolling_max(int *numbers, int numbers_size, int *out, int out_size)
/*@ With lv (numbers0: Z) (numbers_size0: Z) (out0: Z) (out_size0: Z)
    Require
        numbers == numbers0 &&
        numbers_size == numbers_size0 &&
        out == out0 &&
        out_size == out_size0 &&
        0 <= numbers_size0 && numbers_size0 < INT_MAX &&
        out_size0 == numbers_size0 &&
        problem_9_pre &&
        list_int_range(lv) &&
        IntArray::full(numbers, numbers_size, lv) *
        IntArray::undef_full(out, out_size)
    Ensure
        exists output_l,
        __return == out0 &&
        problem_9_pre &&
        problem_9_spec(lv, output_l) &&
        IntArray::full(numbers0, numbers_size0, lv) *
        IntArray::full(out0, out_size0, output_l)
*/
{
    int i;
    int max = -2147483648;

    for (i = 0; i < numbers_size; ++i) {
        if (numbers[i] > max) max = numbers[i];
        out[i] = max;
    }

    return out;
}

